	/*********************************************************************
	*	@function CalculateDollarsAvailableDate
	*	@param 
	*	@see 
	*	@return float
	*********************************************************************/
	/*float*//*C float C*/ function  CalculateDollarsAvailableDate()
	{
		/*To calculate how many dollars are sitting as cash */
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: Money Management*/
		/*	Use Case What: determine how many dollars are available to be used for stock purchase*/
		/*	Use Case Why: Minimize risk and determine how many stocks can be purchased*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		//Depends on the following fields already being set:
		//  username
		//  transactiondate
		//  account (can be NULL or ''
		
		if( !isset( $this->username ))
		  return FALSE;
		if( !isset( $this->transactiondate ))
		  return FALSE;
		
		        $dollar = 0;
		        $this->fieldspec['username']['extra_sql'] = "";
		        $this->orderby = "";
			if( isset( $this->account ))
			{
				if( $this->account <> '' )
					$accountstring = " and account = '" . $this->account . "'";
				else
					$accountstring = "";
			}
		
			$this->querystring = "select sum(dollar) as buy from transaction t, transactiontype tt where t.transactiontype = tt.transactiontype and transactiondate <= '" . $this->transactiondate . "' and " . "stocksymbol = 'CASH' and username = '" . $this->username . "' and AddSub = '1'" . $accountstring;
			$this->GenericQuery();
		        $dollar = $dollar + $this->resultarray[0]['buy'];
		
			$this->querystring = "select sum(dollar) as sell from transaction t, transactiontype tt where t.transactiontype = tt.transactiontype and transactiondate <= '" . $this->transactiondate . "' and " . "stocksymbol = 'CASH' and username = '" . $this->username . "' and AddSub = '-1'" . $accountstring;
			$this->GenericQuery();
		
		        $dollar = $dollar - $this->resultarray[0]['sell'];
		        return $dollar;
		
		//If we don't have a return in the body in codemeta, return
		return 0;
	}
