		/*	Use Case Who: system*/
		/*	Use Case When: purchase transactions in a foreign currency*/
		/*	Use Case What: convert the cash*/
		/*	Use Case Why: accurate pricing*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		fwrite( $flog, "Converting cash from " . $fromdollars . " to " . $todollars . "\n" );
		$this->addtransaction( $flog, $user, "CASH", $fromdollars, $fromdollars, "SELL", $transactiondate, $fromcurrency, $fromcurrency, $account );
		$this->addtransaction( $flog, $user, "CASH", $todollars, $todollars, "BUY", $transactiondate, $tocurrency, $tocurrency, $account );
		
		//If we don't have a return in the body in codemeta, return
		return SUCCESS;
	}
} /* class transaction */

